function SnsRow() {
  return (
    <div className="sns-row">
      <span className="sns-label"><span className="mk">+</span> FOLLOW</span>
      <div className="sns-icons">
        {SNS.map((s) => (
          <a key={s.label} className="sns-icon" href={s.url} target="_blank"
            rel="noopener noreferrer" aria-label={s.label} title={s.label}>
            <SnsIcon name={s.icon} />
          </a>
        ))}
      </div>
    </div>
  );
}

