      <path d="M349.54,507.29h-18.91v-5.63c-5.99,5.27-12.33,7.66-20.23,7.66-18.08,0-31.6-13.53-31.6-31.48s13.53-31.6,31.6-31.6c7.9,0,14.36,2.39,20.23,7.66v-26.46h18.91v79.84ZM297.59,477.72c0,10.06,7.66,18.08,17.24,18.08s17.24-8.02,17.24-17.72c0-10.29-7.54-18.31-17.12-18.31s-17.36,7.9-17.36,17.96Z" />
