      <path d="M695.73,448.27v8.62c5.27-6.82,11.61-10.06,19.99-10.06,1.08,0,1.92.12,3.83.24v15.92c-2.63-.72-4.07-.84-6.11-.84-10.89,0-17.72,6.7-17.72,17.48v27.65h-18.91v-59.02h18.91Z" />
