export default function App() {
  const [page, setPage] = useState("home");
  const [openId, setOpenId] = useState(null);

  useEffect(() => { window.scrollTo({ top: 0, behavior: "auto" }); }, [page]);

  useEffect(() => {
    document.documentElement.lang = "ja";
    document.title = SITE_TITLE;

    const setMeta = (attr, key, content) => {
      if (!content) return;
      let el = document.head.querySelector("meta[" + attr + '="' + key + '"]');
      if (!el) {
        el = document.createElement("meta");
        el.setAttribute(attr, key);
        document.head.appendChild(el);
      }
      el.setAttribute("content", content);
    };

    setMeta("name", "description", SITE_DESC);
    setMeta("property", "og:site_name", "adomiori");
    setMeta("property", "og:title", SITE_TITLE);
    setMeta("property", "og:description", SITE_DESC);
    setMeta("property", "og:type", "website");
    setMeta("property", "og:locale", "ja_JP");
    setMeta("property", "og:url", SITE_URL);
    setMeta("property", "og:image", OG_IMAGE);
    setMeta("name", "twitter:card", OG_IMAGE ? "summary_large_image" : "summary");
    setMeta("name", "twitter:title", SITE_TITLE);
    setMeta("name", "twitter:description", SITE_DESC);
    setMeta("name", "twitter:image", OG_IMAGE);

    const svg =
      '<svg xmlns="http://www.w3.org/2000/svg" viewBox="0 0 1000 1000">' +
      '<path fill="#141B21" d="' + LOGOMARK_PATH + '"/></svg>';
    let icon = document.head.querySelector('link[rel="icon"]');
    if (!icon) {
      icon = document.createElement("link");
      icon.rel = "icon";
      document.head.appendChild(icon);
    }
    icon.type = "image/svg+xml";
    icon.href = "data:image/svg+xml," + encodeURIComponent(svg);
  }, []);

  const openWork = WORKS.find((w) => w.id === openId) || null;

  return (
    <div className="site">
      <style>{CSS}</style>
      <Frame />
      <Nav page={page} setPage={setPage} />
      <main className="stage" key={page}>
        {page === "home" && <Home setPage={setPage} onOpen={setOpenId} />}
        {page === "works" && <Works onOpen={setOpenId} />}
        {page === "biography" && <Biography />}
        {page === "contact" && <Contact />}
      </main>
      <footer className="footer">
        <FooterMark />
        <span className="label"><span className="mk">+</span> N 35.1815 · E 136.9066 — NAGOYA</span>
        <span className="label">© adomiori 2026</span>
      </footer>
      {openWork && <WorkModal key={openWork.id} work={openWork} onClose={() => setOpenId(null)} />}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────
const CSS = `
@import url('https://fonts.googleapis.com/css2?family=Noto+Sans+JP:wght@300;400;500;700&display=swap');

:root{
  --paper:#FCFCFC; --ink:#141B21; --muted:#767B7F;
  --line:#E4E4E2; --faint:#EFEFEE; --accent:#2C6BDB;
  --sans:'Noto Sans JP','Hiragino Kaku Gothic ProN','Yu Gothic',Meiryo,sans-serif;
}
*{box-sizing:border-box;}
.site{background:var(--paper);color:var(--ink);font-family:var(--sans);font-weight:400;min-height:100vh;position:relative;overflow-x:hidden;-webkit-font-smoothing:antialiased;text-rendering:optimizeLegibility;}
button{font-family:inherit;background:none;border:none;cursor:pointer;color:inherit;padding:0;}
a{color:inherit;text-decoration:none;}
img,svg{display:block;}

.label{font-size:10px;font-weight:500;letter-spacing:0.2em;text-transform:uppercase;color:var(--muted);}
.num{font-size:11px;font-weight:500;letter-spacing:0.1em;color:var(--muted);font-variant-numeric:tabular-nums;}
.type{font-size:10px;font-weight:500;letter-spacing:0.15em;text-transform:uppercase;color:var(--muted);}
.mk{color:var(--accent);font-weight:600;}

.frame{position:fixed;inset:clamp(8px,1.4vw,16px);pointer-events:none;z-index:5;}
.tick{position:absolute;width:9px;height:9px;}
.tick::before,.tick::after{content:'';position:absolute;background:var(--line);}
.tick::before{width:9px;height:1px;top:0;}
.tick::after{width:1px;height:9px;left:0;}
.tick.tl{top:0;left:0;}
.tick.tr{top:0;right:0;} .tick.tr::before{right:0;} .tick.tr::after{right:0;left:auto;}
.tick.bl{bottom:0;left:0;} .tick.bl::before{bottom:0;top:auto;}
.tick.br{bottom:0;right:0;} .tick.br::before{bottom:0;top:auto;right:0;} .tick.br::after{right:0;left:auto;bottom:0;}

.nav{position:sticky;top:0;z-index:4;display:flex;justify-content:space-between;align-items:center;gap:18px 40px;flex-wrap:wrap;padding:clamp(20px,3.4vw,34px) clamp(22px,5vw,48px) clamp(16px,2vw,22px);background:linear-gradient(var(--paper) 76%, rgba(252,252,252,0));}
.brand{display:inline-flex;align-items:center;}
.wordmark-svg{width:clamp(116px,20vw,150px);height:auto;color:var(--ink);}
.nav-links{display:flex;gap:clamp(18px,2.6vw,28px);flex-wrap:wrap;}
.nav-link{font-size:10px;font-weight:500;letter-spacing:0.2em;color:var(--muted);position:relative;padding-bottom:4px;transition:color .4s;}
.nav-link:hover{color:var(--ink);}
.nav-link.is-active{color:var(--ink);}
.nav-link.is-active::after{content:'';position:absolute;left:0;bottom:0;width:100%;height:1px;background:var(--accent);}

.stage{max-width:960px;margin:0 auto;padding:clamp(28px,4vw,44px) clamp(22px,5vw,48px) 0;min-height:58vh;}
.page{animation:fade .9s ease both;}
@keyframes fade{from{opacity:0;transform:translateY(10px);}to{opacity:1;transform:none;}}

.rule{height:1px;background:var(--line);margin:clamp(40px,6vw,60px) 0;}
.page-label{display:block;margin-bottom:clamp(38px,6vw,56px);}

.home{padding-top:clamp(4px,1.6vw,16px);}
.hero{margin-bottom:clamp(30px,5vw,44px);}
.hero-line{font-size:clamp(1.55rem,4.6vw,2.6rem);font-weight:700;line-height:1.85;letter-spacing:0.05em;margin:0;}
.hero-stage{position:relative;isolation:isolate;display:flex;align-items:center;padding:clamp(30px,6vw,60px) clamp(20px,4vw,40px);min-height:clamp(190px,32vw,300px);margin-bottom:clamp(20px,3.5vw,30px);}
.hero-media{position:absolute;inset:0;overflow:hidden;background:#0b0f12;}
.hero-video{position:absolute;top:-1px;left:-1px;width:calc(100% + 2px);height:calc(100% + 2px);object-fit:cover;display:block;filter:contrast(1.04) saturate(1.03);}
.hero-lines{position:relative;}
.hero-stage .hero-line{color:#fff;mix-blend-mode:difference;}
.hero-latin{font-size:clamp(.82rem,1.8vw,1rem);font-weight:400;color:var(--muted);letter-spacing:0.06em;margin-top:clamp(22px,4vw,32px);}
.hero .hero-latin{font-size:clamp(.77rem,1.6vw,.93rem);}
.hero-trace{display:block;width:clamp(90px,16vw,168px);height:0;border-top:1px dashed var(--accent);opacity:.45;margin-top:clamp(26px,4vw,34px);}

.sns-row{display:flex;align-items:center;gap:18px;flex-wrap:wrap;margin:clamp(28px,4.5vw,40px) 0 0;}
.sns-label{font-size:10px;font-weight:500;letter-spacing:0.2em;text-transform:uppercase;color:var(--muted);display:flex;align-items:center;gap:8px;}
.sns-icons{display:flex;align-items:center;gap:18px;}
.sns-icon{color:var(--muted);transition:color .3s,transform .3s;line-height:0;display:inline-flex;}
.sns-icon:hover{color:var(--accent);transform:translateY(-2px);}
.sns-icon svg{width:19px;height:19px;display:block;}

.home-index{display:flex;flex-direction:column;gap:clamp(24px,4vw,30px);}
.home-lower{display:grid;grid-template-columns:minmax(0,0.82fr) minmax(0,1fr);gap:clamp(28px,5vw,52px);align-items:stretch;}
.store-banner{position:relative;display:flex;flex-direction:column;justify-content:flex-end;min-height:clamp(190px,26vw,280px);padding:clamp(20px,3vw,30px);overflow:hidden;border:1px solid var(--line);isolation:isolate;transition:opacity .35s;}
.store-banner:hover{opacity:.94;}
.store-media{position:absolute;inset:0;z-index:0;background:linear-gradient(140deg,#1c2530 0%,#2b3a46 58%,#141b21 100%);}
.store-media img{width:100%;height:100%;object-fit:cover;display:block;}
.store-slide{position:absolute;inset:0;width:100%;height:100%;object-fit:cover;opacity:0;transition:opacity 1s ease;}
.store-slide.is-active{opacity:1;}
.store-scrim{position:absolute;inset:0;box-shadow:inset 0 0 clamp(30px,7vw,78px) clamp(4px,1.2vw,12px) rgba(0,0,0,.42);background:radial-gradient(135% 130% at 50% 42%, rgba(0,0,0,0) 48%, rgba(0,0,0,.16) 78%, rgba(0,0,0,.32) 100%), linear-gradient(to top, rgba(0,0,0,.5) 0%, rgba(0,0,0,.14) 48%, rgba(0,0,0,0) 74%);}
.store-body{position:relative;z-index:1;display:flex;flex-direction:column;gap:6px;color:#fff;}
.store-body .label{color:rgba(255,255,255,.74);}
.store-title{font-size:clamp(1.1rem,2.4vw,1.4rem);font-weight:700;letter-spacing:0.04em;line-height:1.5;margin:4px 0 0;}
.store-sub{font-size:.8rem;font-weight:400;color:rgba(255,255,255,.72);letter-spacing:0.04em;margin:0;}
.store-cta{font-size:11px;font-weight:500;letter-spacing:0.12em;text-transform:uppercase;margin-top:12px;display:inline-flex;align-items:center;gap:8px;}
.store-cta .arrow{color:#fff;transition:transform .35s;}
.store-banner:hover .store-cta .arrow{transform:translateX(5px);}
@media(max-width:760px){.home-lower{grid-template-columns:1fr;gap:clamp(26px,6vw,34px);}.home-lower .home-index{order:-1;}.store-banner{min-height:clamp(170px,44vw,220px);}}
.idx-row{display:flex;flex-direction:column;gap:12px;}
.idx-link{display:flex;align-items:baseline;gap:14px 20px;text-align:left;flex-wrap:wrap;transition:opacity .3s;}
.idx-link:hover{opacity:.55;}
.idx-title{font-size:clamp(1rem,2.4vw,1.15rem);font-weight:500;letter-spacing:0.05em;}
.arrow{font-weight:500;}
.idx-link .arrow{color:var(--accent);transition:transform .35s;}
.idx-link:hover .arrow{transform:translateX(6px);}

.filters{display:flex;flex-direction:column;gap:18px;margin-bottom:clamp(38px,6vw,52px);}
.filter-group{display:flex;align-items:center;flex-wrap:wrap;gap:12px 16px;}
.filter-name{width:44px;flex-shrink:0;}
.filter-btn{font-size:11px;font-weight:500;letter-spacing:0.1em;color:var(--muted);padding-bottom:3px;border-bottom:1px solid transparent;transition:color .3s,border-color .3s;}
.filter-btn:hover{color:var(--ink);}
.filter-btn.is-active{color:var(--ink);border-color:var(--accent);}

.catalogue{display:flex;flex-direction:column;gap:clamp(40px,6vw,56px);}
.empty{color:var(--muted);font-weight:400;}
.year-block{display:grid;grid-template-columns:70px 1fr;gap:4px;}
.year-mark{padding-top:20px;font-size:12px;}
.year-items{display:flex;flex-direction:column;}

.work-head{display:grid;grid-template-columns:40px 1fr auto 22px;align-items:baseline;gap:12px 16px;width:100%;text-align:left;padding:20px 0;border-top:1px solid var(--line);transition:opacity .3s;}
.year-items .work-head:last-child{border-bottom:1px solid var(--line);}
.work-head:hover{opacity:.6;}
.work-title{font-size:clamp(.98rem,2.2vw,1.08rem);font-weight:500;letter-spacing:0.03em;line-height:1.55;}
.work-open{font-size:12px;color:var(--muted);text-align:right;transition:color .3s;}
.work-head:hover .work-open{color:var(--accent);}
.work-link{font-size:11px;font-weight:500;letter-spacing:0.08em;border-bottom:1px solid var(--line);padding-bottom:2px;transition:border-color .3s;}
.work-link:hover{border-color:var(--accent);}
.work-link .arrow{color:var(--accent);}

.modal-overlay{position:fixed;inset:0;z-index:20;background:rgba(20,27,33,0.55);display:flex;align-items:center;justify-content:center;padding:clamp(16px,4vw,40px);animation:overlayin .35s ease both;}
@keyframes overlayin{from{opacity:0;}to{opacity:1;}}
.modal-card{position:relative;background:var(--paper);border:1px solid var(--line);width:min(720px,94vw);max-height:88vh;overflow-y:auto;padding:clamp(24px,4vw,40px);animation:cardin .4s cubic-bezier(.2,.7,.2,1) both;}
@keyframes cardin{from{opacity:0;transform:translateY(12px);}to{opacity:1;transform:none;}}
.modal-close{position:absolute;top:14px;right:16px;font-size:22px;line-height:1;color:var(--muted);font-weight:300;transition:color .3s;z-index:2;}
.modal-close:hover{color:var(--accent);}
.modal-meta{display:flex;align-items:center;gap:14px;margin-bottom:14px;}
.modal-title{font-size:clamp(1.15rem,3vw,1.5rem);font-weight:700;letter-spacing:0.03em;line-height:1.5;margin:0 0 6px;padding-right:24px;}
.modal-latin{font-size:10px;font-weight:500;letter-spacing:0.15em;text-transform:uppercase;color:var(--muted);margin:0 0 22px;}
.video-wrap{position:relative;width:100%;padding-top:56.25%;margin:0 0 22px;background:#000;border:1px solid var(--line);overflow:hidden;}
.video-wrap iframe{position:absolute;top:-1px;left:-1px;width:calc(100% + 2px);height:calc(100% + 2px);border:0;display:block;}
.video-facade{position:absolute;inset:0;width:100%;height:100%;padding:0;overflow:hidden;display:block;background:#000;cursor:pointer;}
.video-yt{position:absolute;left:0;bottom:0;margin:12px;font-size:10px;font-weight:500;letter-spacing:0.12em;text-transform:uppercase;color:#fff;background:rgba(20,27,33,.6);padding:6px 10px;transition:background .3s;}
.video-yt:hover{background:var(--accent);}
.video-facade img{width:100%;height:100%;object-fit:cover;display:block;opacity:.92;transition:opacity .3s;}
.video-facade:hover img{opacity:1;}
.video-play{position:absolute;top:50%;left:50%;transform:translate(-50%,-50%);width:58px;height:58px;border-radius:50%;background:rgba(20,27,33,.72);color:#fff;display:flex;align-items:center;justify-content:center;font-size:19px;padding-left:4px;transition:background .3s,transform .3s;}
.video-facade:hover .video-play{background:var(--accent);transform:translate(-50%,-50%) scale(1.06);}
.modal-credit{font-size:.85rem;font-weight:400;color:var(--muted);letter-spacing:0.03em;margin:0 0 20px;line-height:1.8;}
.modal-links{display:flex;align-items:center;flex-wrap:wrap;gap:14px 22px;}
.modal-link-row{display:flex;align-items:center;flex-wrap:wrap;gap:12px 22px;}
.modal-card:focus{outline:none;}
@media(max-width:560px){
  .modal-links{flex-direction:column;align-items:flex-start;gap:12px;}
  .modal-link-row{gap:10px 18px;}
  .modal-link-row .work-link{font-size:10.5px;letter-spacing:0.06em;}
}

.bio-top{display:grid;grid-template-columns:1fr minmax(240px,320px);gap:clamp(28px,5vw,56px);align-items:start;margin-bottom:clamp(44px,7vw,68px);}
.bio-lead-label{display:block;margin-bottom:22px;}
.bio-portrait{margin:0;}
.bio-slider .portrait-frame{position:relative;aspect-ratio:1/1;overflow:hidden;cursor:grab;touch-action:pan-y;user-select:none;padding:0;}
.bio-slider .portrait-frame:active{cursor:grabbing;}
.plate-stage{position:absolute;inset:0;padding:12px;display:grid;place-items:center;}
.plate-img{grid-area:1/1;opacity:0;transition:opacity .5s ease;-webkit-user-drag:none;user-select:none;pointer-events:none;}
.plate-img.fit-contain{max-width:100%;max-height:100%;object-fit:contain;}
.plate-img.fit-cover{width:100%;height:100%;object-fit:cover;}
.plate-img.is-active{opacity:1;}
.plate-nav{position:absolute;top:50%;transform:translateY(-50%);width:34px;height:34px;display:flex;align-items:center;justify-content:center;font-size:20px;line-height:1;color:var(--ink);background:rgba(252,252,252,.82);border:1px solid var(--line);opacity:0;transition:opacity .3s,color .3s,border-color .3s;}
.plate-nav.prev{left:8px;} .plate-nav.next{right:8px;}
.plate-nav:hover{color:var(--accent);border-color:var(--accent);}
.bio-slider:hover .plate-nav,.plate-nav:focus-visible{opacity:1;}
.portrait-cap{display:flex;align-items:center;justify-content:space-between;gap:12px;margin-top:12px;}
.plate-dots{display:flex;align-items:center;gap:8px;}
.plate-dot{width:7px;height:7px;border-radius:50%;background:transparent;border:1px solid var(--muted);transition:background .3s,border-color .3s;padding:0;}
.plate-dot.is-active{background:var(--accent);border-color:var(--accent);}
.portrait-frame{position:relative;padding:12px;border:1px solid var(--line);background:#fff;}
.portrait-frame img{width:100%;height:auto;display:block;}
.pt{position:absolute;width:7px;height:7px;}
.pt::before,.pt::after{content:'';position:absolute;background:var(--accent);}
.pt::before{width:7px;height:1px;top:0;}
.pt::after{width:1px;height:7px;left:0;}
.pt.tl{top:-1px;left:-1px;}
.pt.tr{top:-1px;right:-1px;} .pt.tr::before{right:0;} .pt.tr::after{right:0;left:auto;}
.pt.bl{bottom:-1px;left:-1px;} .pt.bl::before{bottom:0;top:auto;}
.pt.br{bottom:-1px;right:-1px;} .pt.br::before{bottom:0;top:auto;right:0;} .pt.br::after{right:0;left:auto;bottom:0;}
.portrait-cap{display:flex;align-items:center;gap:8px;margin-top:12px;}

.profile{display:flex;flex-direction:column;gap:clamp(30px,5vw,38px);}
.prof-row{display:grid;grid-template-columns:110px 1fr;gap:12px 20px;align-items:start;}
.prof-text{margin:0;font-size:.92rem;font-weight:400;line-height:2.05;letter-spacing:0.04em;max-width:54ch;}
.prof-bio p{margin:0 0 16px;}
.prof-bio p:last-child{margin-bottom:0;}
.prof-bio .en{color:var(--muted);font-weight:400;line-height:1.9;letter-spacing:0.02em;font-size:.86rem;}
.bio-divider{display:block;height:0;border-top:1px dashed var(--line);margin:26px 0;max-width:54ch;}
.prof-list{margin:0;padding:0;list-style:none;display:flex;flex-direction:column;gap:12px;}
.prof-list li{font-size:.9rem;font-weight:400;letter-spacing:0.04em;padding-left:16px;position:relative;line-height:1.7;}
.prof-list li::before{content:'—';position:absolute;left:0;color:var(--accent);}

.bio-slider .plate-nav{opacity:1;}
@media(hover:hover){.bio-slider .plate-nav{opacity:0;}}
.contact-lead .lead-line{font-size:clamp(1.1rem,2.8vw,1.5rem);font-weight:500;line-height:1.85;letter-spacing:0.05em;margin:0 0 14px;}
.contact-mail{font-size:clamp(1rem,2.4vw,1.1rem);font-weight:500;letter-spacing:0.04em;border-bottom:1px solid var(--line);padding-bottom:3px;transition:border-color .3s;display:inline-block;word-break:break-all;}
.contact-mail:hover{border-color:var(--accent);}
.mock-form{display:flex;flex-direction:column;gap:22px;max-width:440px;}
.field{display:flex;flex-direction:column;gap:8px;}
.field-label{font-size:9px;font-weight:500;letter-spacing:0.2em;text-transform:uppercase;color:var(--muted);}
.field-input{background:transparent;border:none;border-bottom:1px solid var(--line);padding:8px 0;font-family:var(--sans);font-size:.92rem;font-weight:400;color:var(--ink);outline:none;transition:border-color .3s;resize:none;width:100%;}
.field-input:focus{border-color:var(--accent);}
.field-send{font-size:11px;font-weight:500;letter-spacing:0.14em;border-bottom:1px solid var(--ink);padding-bottom:3px;align-self:flex-start;margin-top:6px;transition:opacity .3s;}
.field-send:hover{opacity:.55;}
.field-send .arrow{color:var(--accent);}
.field-note{margin-top:4px;}
.mail-row{display:flex;align-items:center;gap:16px 18px;flex-wrap:wrap;}
.copy-btn{font-size:10px;font-weight:500;letter-spacing:0.18em;text-transform:uppercase;color:var(--muted);border:1px solid var(--line);padding:8px 15px;transition:color .3s,border-color .3s,background .3s;}
.copy-btn:hover{color:var(--ink);border-color:var(--accent);}
.contact-note{font-size:.78rem;line-height:1.9;}
.marquee{width:100vw;margin-left:calc(50% - 50vw);margin-top:clamp(64px,11vw,120px);padding:clamp(16px,2.6vw,24px) 0;overflow:hidden;border-top:1px solid var(--faint);border-bottom:1px solid var(--faint);pointer-events:none;user-select:none;-webkit-tap-highlight-color:transparent;}
.marquee-track{display:flex;align-items:center;width:max-content;animation:marquee 60s linear infinite;}
@keyframes marquee{from{transform:translateX(0);}to{transform:translateX(-50%);}}
.marquee-img{height:clamp(120px,20vw,220px);width:auto;display:block;flex:0 0 auto;margin-right:clamp(10px,1.6vw,20px);object-fit:cover;}
.marquee-ph{flex:0 0 auto;padding:clamp(22px,4vw,38px) 0;font-size:11px;font-weight:500;letter-spacing:0.22em;color:var(--muted);white-space:nowrap;font-variant-numeric:tabular-nums;text-transform:uppercase;}

.footer{max-width:960px;margin:clamp(80px,14vw,120px) auto 0;padding:26px clamp(22px,5vw,48px) 44px;border-top:1px solid var(--faint);display:flex;align-items:center;justify-content:space-between;gap:12px 16px;flex-wrap:wrap;}
.footer-mark{width:clamp(84px,11vw,104px);height:auto;color:var(--ink);display:block;}
.prof-meta{margin:0 0 clamp(20px,3vw,28px);font-size:.78rem;line-height:1.95;letter-spacing:0.04em;color:var(--ink);}
.footer .label{display:flex;align-items:center;gap:8px;font-variant-numeric:tabular-nums;}

@media(max-width:760px){
  .nav{align-items:flex-start;}
  .bio-top{grid-template-columns:1fr;gap:clamp(26px,6vw,34px);}
  .bio-portrait{order:-1;max-width:320px;}
  .bio-lead-label{margin-bottom:16px;}
  .year-block{grid-template-columns:1fr;gap:12px;}
  .year-mark{padding-top:0;}
  .work-head{grid-template-columns:32px 1fr 20px;}
  .work-type{display:none;}
  .prof-row{grid-template-columns:1fr;gap:8px;}
}
@media(max-width:440px){
  .idx-link .type{display:none;}
  .footer{flex-direction:column;align-items:flex-start;}
}
@media(prefers-reduced-motion:reduce){
  .page,.modal-overlay,.modal-card{animation:none;}
  .marquee-track{animation:none;}
  *{transition:none !important;}
}
`;
